import{_ as e,c as r,o as t,ai as o}from"./chunks/framework.TS84ywiI.js";const c=JSON.parse('{"title":"如何按照 query 的频度排序？","description":"","frontmatter":{},"headers":[],"relativePath":"big-data/sort-the-query-strings-by-counts.md","filePath":"big-data/sort-the-query-strings-by-counts.md"}'),s={name:"big-data/sort-the-query-strings-by-counts.md"};function u(h,a,i,n,l,q){return t(),r("div",null,a[0]||(a[0]=[o('<h1 id="如何按照-query-的频度排序" tabindex="-1">如何按照 query 的频度排序？ <a class="header-anchor" href="#如何按照-query-的频度排序" aria-label="Permalink to &quot;如何按照 query 的频度排序？&quot;">​</a></h1><h2 id="题目描述" tabindex="-1">题目描述 <a class="header-anchor" href="#题目描述" aria-label="Permalink to &quot;题目描述&quot;">​</a></h2><p>有 10 个文件，每个文件大小为 1G，每个文件的每一行存放的都是用户的 query，每个文件的 query 都可能重复。要求按照 query 的频度排序。</p><h2 id="解答思路" tabindex="-1">解答思路 <a class="header-anchor" href="#解答思路" aria-label="Permalink to &quot;解答思路&quot;">​</a></h2><p>如果 query 的重复度比较大，可以考虑一次性把所有 query 读入内存中处理；如果 query 的重复率不高，那么可用内存不足以容纳所有的 query，这时候就需要采用分治法或其他的方法来解决。</p><h3 id="方法一-hashmap-法" tabindex="-1">方法一：HashMap 法 <a class="header-anchor" href="#方法一-hashmap-法" aria-label="Permalink to &quot;方法一：HashMap 法&quot;">​</a></h3><p>如果 query 重复率高，说明不同 query 总数比较小，可以考虑把所有的 query 都加载到内存中的 HashMap 中。接着就可以按照 query 出现的次数进行排序。</p><h3 id="方法二-分治法" tabindex="-1">方法二：分治法 <a class="header-anchor" href="#方法二-分治法" aria-label="Permalink to &quot;方法二：分治法&quot;">​</a></h3><p>分治法需要根据数据量大小以及可用内存的大小来确定问题划分的规模。对于这道题，可以顺序遍历 10 个文件中的 query，通过 Hash 函数 <code>hash(query) % 10</code> 把这些 query 划分到 10 个小文件中。之后对每个小文件使用 HashMap 统计 query 出现次数，根据次数排序并写入到另外一个单独文件中。</p><p>接着对所有文件按照 query 的次数进行排序，这里可以使用归并排序（由于无法把所有 query 都读入内存，因此需要使用外排序）。</p><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><ul><li>内存若够，直接读入进行排序；</li><li>内存不够，先划分为小文件，小文件排好序后，整理使用外排序进行归并。</li></ul>',12)]))}const y=e(s,[["render",u]]);export{c as __pageData,y as default};
